const input = $json || {};
const str = (v) => (v === null || v === undefined ? '' : String(v).trim());
const toLower = (v) => str(v).toLowerCase();

const name = str(input.Name || input.name) || 'Unknown Lead';
const email = str(input.Email || input.email).toLowerCase();
const business = str(input.Business || input.business) || 'Not provided';
const selectedPackage = str(input['Select Package'] || input.package || input.selectedPackage) || 'Not provided';
const automationRequest = str(input['Automation Request'] || input.automationRequest || input.need || input.projectNeed) || 'Not provided';

const source = str(input.source || input.form || input.formName || 'System Capital Form');
const receivedAt = new Date().toISOString();
const leadId = `lead_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

const pkgLower = toLower(selectedPackage);
const reqLower = toLower(automationRequest);
const urgentTerms = ['asap', 'urgent', 'immediately', 'today'];

const highByPackage = pkgLower.includes('full') || pkgLower.includes('$149') || pkgLower.includes('custom');
const highByUrgency = urgentTerms.some(t => reqLower.includes(t));
const priority = (highByPackage || highByUrgency) ? 'High' : 'Normal';

const rawPreview = JSON.stringify(input).slice(0, 1200);

return [{
  json: {
    leadId,
    name,
    email,
    business,
    package: selectedPackage,
    automationRequest,
    source,
    receivedAt,
    priority,
    emailExists: !!email,
    rawPreview
  }
}];

